import React from 'react';
import { Navbar, Nav, Container, NavLink } from 'react-bootstrap';

const Header = () => {
  return (
    <Navbar bg="light" variant="light" expand="lg">
      <Container>
        <Navbar.Toggle aria-controls="basic-navbar-nav" />
        <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="m-auto" variant="tabs">
            <Nav.Link as={NavLink} href="/" eventKey="home">Home</Nav.Link>
            <Nav.Link as={NavLink} href="/resume" eventKey="resume">Resume</Nav.Link>
            <Nav.Link as={NavLink} href="/publications" eventKey="publications">Publications</Nav.Link>
            <Nav.Link as={NavLink} href="/contact" eventKey="contact">Contact</Nav.Link>
          </Nav>
        </Navbar.Collapse>
      </Container>
    </Navbar>
  );
};

export default Header;
